# grafana-dashboard-platform-metrics.yaml
apiVersion: v1
kind: ConfigMap
metadata:
  name: platform-metrics-dashboard
  labels:
    grafana_dashboard: "true"
data:
  platform-metrics.json: |
    {
      "title": "IDP Health & Adoption",
      "panels": [
        {
          "title": "Self-Service vs Ticket Requests (Weekly)",
          "type": "timeseries",
          "targets": [{
            "expr": "sum(rate(platform_self_service_requests_total[7d]))",
            "legendFormat": "Self-service"
          }, {
            "expr": "sum(rate(platform_ticket_requests_total[7d]))",
            "legendFormat": "Manual tickets"
          }]
        },
        {
          "title": "Time to First Deploy (New Services)",
          "type": "stat",
          "targets": [{
            "expr": "histogram_quantile(0.50, platform_service_creation_duration_seconds_bucket)",
            "legendFormat": "p50 creation time"
          }]
        },
        {
          "title": "Golden Path Adoption Rate",
          "type": "gauge",
          "targets": [{
            "expr": "sum(platform_services_on_golden_path) / sum(platform_services_total) * 100",
            "legendFormat": "% on golden path"
          }]
        },
        {
          "title": "Developer Satisfaction (Quarterly Survey)",
          "type": "stat",
          "targets": [{
            "expr": "platform_developer_satisfaction_score",
            "legendFormat": "Satisfaction (1-10)"
          }]
        }
      ]
    }
